def parse_names(value):
    return ''.join(value.split())

# Test cases
class QueryTestCase(unittest.TestCase):
    def test_parse_names(self):
        self.assertEqual(parse_names("John Doe"), "JohnDoe")
        self.assertEqual(parse_names("   John   Doe   "), "JohnDoe")
        self.assertEqual(parse_names("John\nDoe"), "JohnDoe")
        self.assertEqual(parse_names("John\rDoe"), "JohnDoe")
        self.assertEqual(parse_names("John\r\nDoe"), "JohnDoe")
        self.assertEqual(parse_names(""), "")
        self.assertEqual(parse_names("   "), "")
        self.assertEqual(parse_names("John Doe\nJane Smith"), "JohnDoeJaneSmith")

if __name__ == "__main__":
    unittest.main()
